import novamind_api as nm, json
for gid in ['E2','E3','D_E07','D_E02','D_E03','D_E01','D_E08','D_E10','S2','S3','D_S07']:
    try:
        ins=nm.market.get_group_insights(group_id=gid)
        print(gid, ins.get('group_name'), 'info', ins.get('info_level'), 'noise', ins.get('noise'))
        print(json.dumps(ins.get('estimates'), sort_keys=True))
    except Exception as e:
        print(gid,e)
